	@Test
	void conjunctiveExactRelationsIntersectTheirSharedFiniteDomain() {
		Value a1 = iri("urn:test:a1");
		Value a2 = iri("urn:test:a2");
		Value b1 = iri("urn:test:b1");
		Value b2 = iri("urn:test:b2");
		Value b3 = iri("urn:test:b3");
		Value c1 = iri("urn:test:c1");
		Value c2 = iri("urn:test:c2");
		BindingProfile leftRelation = exactProfile(List.of("a", "b"),
				List.of(List.of(a1, b1), List.of(a2, b2)), "left-exact-relation");
		BindingProfile selectedRelation = exactProfile(List.of("b", "c"),
				List.of(List.of(b2, c1), List.of(b3, c2)), "selected-exact-relation");
		InputBindingContext inherited = InputBindingContext.fromProfile(2.0d, Set.of("a", "b"), leftRelation);
		StatementPattern selectedPlan = pattern("b", "predicate", "c");
		MemoExpr expression = new MemoExpr(1, 1, "StatementPattern", List.of(), "prefix-scan", selectedPlan,
				PhysicalProperties.ANY, RuleKind.IMPLEMENTATION, CostVector.ZERO, List.of(), "prefix-scan");
		Winner selected = new Winner(expression, selectedPlan.clone(), PhysicalProperties.ANY,
				new CostVector(2.0d, 2.0d, 0.0d, 0.0d, 0.0d, 1.0d, 1.0d), List.of(), false, "", null,
				inherited, CostScope.PER_INVOCATION, 2.0d, selectedRelation, Set.of("b", "c"));

		InputBindingContext context = InputBindingContext.selectedPrefix(inherited, selected, Set.of("b", "c"),
				BindingProfile.ANY, Set.of("a", "b", "c"));

		assertEquals(Set.of(b2), context.finiteBindingValues(Set.of("b")).get("b"),
				"Exact relations are conjuncts; shared lookup keys must have support in every relation");
	}

