	@Test
	void locallyCheaperHighRowWinnerDoesNotDominateCheaperParentComposition() {
		Memo memo = new Memo(CascadesCostModel.from(new EvaluationStatistics()));
		StatementPattern pattern = pattern("s", "p", "o");
		int groupId = memo.intern(pattern);
		MemoExpr expression = memo.group(groupId).expressions().getFirst();
		PhysicalProperties delivered = physicalProperties(BindingProfile.ANY);
		Winner highRows = winner(expression, pattern, delivered, 100.0d, 1.0d);
		Winner lowRows = winner(expression, pattern, delivered, 1.0d, 2.0d);

		assertTrue(highRows.cost().compareTo(lowRows.cost()) < 0,
				"The high-row child is deliberately cheaper in isolation");
		assertTrue(lookupParentTotalCost(lowRows, lowRows.cost().rows() * 100.0d)
				.compareTo(lookupParentTotalCost(highRows, highRows.cost().rows() * 100.0d)) < 0,
				"The low-row child makes a row-sensitive parent globally cheaper");
		assertTrue(memo.addWinner(OptimizationGoal.root().key(groupId), highRows, 8, true));
		assertTrue(memo.addWinner(OptimizationGoal.root().key(groupId), lowRows, 8, true),
				"Standalone objective and output rows must form a Pareto frontier for parent costing");
	}

	@Test
	void selectedOutputRowsAreParetoDimensionNotFrontierPartition() {
		Memo memo = new Memo(CascadesCostModel.from(new EvaluationStatistics()));
		StatementPattern pattern = pattern("s", "p", "o");
		int groupId = memo.intern(pattern);
		MemoExpr expression = memo.group(groupId).expressions().getFirst();
		PhysicalProperties delivered = physicalProperties(BindingProfile.ANY);
		CostVector sameCanonicalCost = new CostVector(20.0d, 20.0d, 0.0d, 0.0d, 0.0d, 1.0d, 1.0d);
		Winner higherSelectedRows = explicitSelectedWinner(expression, pattern, delivered, sameCanonicalCost, 20.0d);
		Winner lowerSelectedRows = explicitSelectedWinner(expression, pattern, delivered, sameCanonicalCost, 10.0d);
		WinnerKey key = OptimizationGoal.root().key(groupId);

		assertTrue(memo.addWinner(key, higherSelectedRows, 8, true));
		assertTrue(memo.addWinner(key, lowerSelectedRows, 8, true));
		assertEquals(List.of(lowerSelectedRows), memo.winners(key),
				"A no-worse winner with fewer selected output rows must replace the dominated parent-cost state");

		Memo tradeoffMemo = new Memo(CascadesCostModel.from(new EvaluationStatistics()));
		int tradeoffGroupId = tradeoffMemo.intern(pattern.clone());
		MemoExpr tradeoffExpression = tradeoffMemo.group(tradeoffGroupId).expressions().getFirst();
		Winner cheaperHigherRows = explicitSelectedWinner(tradeoffExpression, pattern, delivered,
				new CostVector(20.0d, 10.0d, 0.0d, 0.0d, 0.0d, 1.0d, 1.0d), 20.0d);
		Winner costlierLowerRows = explicitSelectedWinner(tradeoffExpression, pattern, delivered,
				new CostVector(20.0d, 20.0d, 0.0d, 0.0d, 0.0d, 1.0d, 1.0d), 10.0d);
		WinnerKey tradeoffKey = OptimizationGoal.root().key(tradeoffGroupId);

		assertTrue(tradeoffMemo.addWinner(tradeoffKey, cheaperHigherRows, 8, true));
		assertTrue(tradeoffMemo.addWinner(tradeoffKey, costlierLowerRows, 8, true));
		assertEquals(2, tradeoffMemo.winners(tradeoffKey).size(),
				"Standalone cost and selected output cardinality remain independent Pareto dimensions");
	}

	@Test
	void statisticalEvidenceDoesNotSplitOptimizationGoalIdentity() {
		PhysicalProperties firstEvidence = physicalProperties(finiteProfile("o", iri("urn:test:first")));
		PhysicalProperties refinedEvidence = physicalProperties(finiteProfile("o", iri("urn:test:second")));

		OptimizationGoal firstGoal = OptimizationGoal.exact(firstEvidence);
		OptimizationGoal refinedGoal = OptimizationGoal.exact(refinedEvidence);

		assertEquals(firstGoal, refinedGoal,
				"Cardinality evidence must not create a distinct executable optimization goal");
		assertEquals(firstGoal.key(7), refinedGoal.key(7),
				"Cardinality evidence must not create a distinct contextual winner frontier");
		assertEquals(
				new WinnerKey(7, firstEvidence, OptimizationGoal.BAG_SEMANTICS,
						OptimizationGoal.CostPolicy.EXACT),
				new WinnerKey(7, refinedEvidence, OptimizationGoal.BAG_SEMANTICS,
						OptimizationGoal.CostPolicy.EXACT),
				"Winner keys must defensively discard statistical evidence");

		StatementPattern fromStart = pattern("s", "p", "o");
		fromStart.setStringMetricPlanned("plannedPropertyPathEndpointMode", "fromStart");
		PhysicalProperties endpointOnly = PhysicalProperties.builder()
				.accessPath("propertyPath")
				.bindingProfile(BindingProfile.endpointOnly(fromStart))
				.build();
		PhysicalProperties endpointWithEvidence = PhysicalProperties.builder()
				.accessPath("propertyPath")
				.bindingProfile(withEndpointMode(firstGoal.requiredProperties().bindingProfile(), "fromStart"))
				.build();
		assertEquals(OptimizationGoal.exact(endpointOnly), OptimizationGoal.exact(endpointWithEvidence),
				"Equal endpoint contracts must not retain different evidence profiles");

		StatementPattern toEnd = pattern("s", "p", "o");
		toEnd.setStringMetricPlanned("plannedPropertyPathEndpointMode", "toEnd");
		PhysicalProperties oppositeEndpoint = PhysicalProperties.builder()
				.accessPath("propertyPath")
				.bindingProfile(BindingProfile.endpointOnly(toEnd))
				.build();
		assertNotEquals(OptimizationGoal.exact(endpointOnly), OptimizationGoal.exact(oppositeEndpoint),
				"Different endpoint orientations remain distinct executable contracts");
	}

