	void joinDoesNotDeliverAChildAccessPath() {
		CascadesCostModel model = CascadesCostModel.from(new EvaluationStatistics());
		StatementPattern leftPattern = pattern("s", "left", "o");
		StatementPattern rightPattern = pattern("o", "right", "x");
		Join join = new Join(leftPattern, rightPattern);
		MemoExpr physicalJoin = new MemoExpr(20, 0, "Join", List.of(1, 2), "join", join,
				PhysicalProperties.ANY, RuleKind.IMPLEMENTATION, CostVector.ZERO, List.of(), "physical-join");
		Winner left = leafWinner(1, leftPattern, "leftPrefixScan");
		Winner right = leafWinner(2, rightPattern, "rightDirectLookup");

		PhysicalProperties delivered = model.deliveredProperties(physicalJoin, OptimizationGoal.root(),
				List.of(left, right));

		assertEquals(PhysicalProperties.ANY_ACCESS_PATH, delivered.accessPath(),
				"A binary operator must deliver its own access contract, not whichever leaf became its left input");
	}

	@Test
	void endpointOrientationRemainsPartOfTheExecutableContract() {
		Memo memo = new Memo(CascadesCostModel.from(new EvaluationStatistics()));
		StatementPattern logical = pattern("s", "p", "o");
		int groupId = memo.intern(logical);
		StatementPattern fromStart = pattern("s", "p", "o");
		fromStart.setStringMetricPlanned("plannedPropertyPathEndpointMode", "fromStart");
		StatementPattern toEnd = pattern("s", "p", "o");
		toEnd.setStringMetricPlanned("plannedPropertyPathEndpointMode", "toEnd");
		PhysicalProperties fromStartProperties = PhysicalProperties.builder()
				.accessPath("propertyPath")
				.bindingProfile(BindingProfile.endpointOnly(fromStart))
				.build();
		PhysicalProperties toEndProperties = PhysicalProperties.builder()
				.accessPath("propertyPath")
				.bindingProfile(BindingProfile.endpointOnly(toEnd))
				.build();

		MemoExpr fromStartExpression = memo.addPhysicalAlternative(groupId, fromStart, fromStartProperties,
				"property-path", RuleKind.IMPLEMENTATION, CostVector.ZERO, List.of()).orElseThrow();
		MemoExpr toEndExpression = memo.addPhysicalAlternative(groupId, toEnd, toEndProperties, "property-path",
				RuleKind.IMPLEMENTATION, CostVector.ZERO, List.of()).orElseThrow();
		WinnerKey key = OptimizationGoal.root().key(groupId);

		assertTrue(memo.addWinner(key, winner(fromStartExpression, fromStart, fromStartProperties, 1.0d), 8, true));
		assertTrue(memo.addWinner(key, winner(toEndExpression, toEnd, toEndProperties, 1.0d), 8, true));
		assertEquals(2, memo.winners(key).size(),
				"Property-path endpoint orientation remains an executable contract after statistics are separated");
	}

	private static PhysicalProperties physicalProperties(BindingProfile bindingProfile) {
		return PhysicalProperties.builder()
				.accessPath("prefixScan")
				.bindingProfile(bindingProfile)
				.build();
	}

	private static Winner leafWinner(int id, StatementPattern pattern, String accessPath) {
		PhysicalProperties delivered = PhysicalProperties.builder()
				.accessPath(accessPath)
				.boundVars(pattern.getBindingNames())
				.bindingProfile(finiteProfile(pattern.getObjectVar().getName(), iri("urn:test:" + id)))
				.build();
		MemoExpr expression = new MemoExpr(id, id, "StatementPattern", List.of(), accessPath, pattern, delivered,
				RuleKind.IMPLEMENTATION, CostVector.ZERO, List.of(), "leaf-" + id);
		return winner(expression, pattern, delivered, 1.0d);
	}

	private static Winner winner(MemoExpr expression, StatementPattern plan, PhysicalProperties delivered,
			double cost) {
		return winner(expression, plan, delivered, cost, cost);
	}

	private static Winner winner(MemoExpr expression, StatementPattern plan, PhysicalProperties delivered,
			double rows, double workRows) {
		CostVector vector = new CostVector(rows, workRows, 0.0d, 0.0d, 0.0d, 1.0d, 1.0d);
		return new Winner(expression, plan.clone(), delivered, vector, List.of(), false, "");
	}

	private static Winner explicitSelectedWinner(MemoExpr expression, StatementPattern plan,
			PhysicalProperties delivered, CostVector canonicalCost, double selectedOutputRows) {
		return new Winner(expression, plan.clone(), delivered, canonicalCost, List.of(), false, "", null,
				InputBindingContext.NONE, CostScope.PER_INVOCATION, selectedOutputRows, BindingProfile.ANY,
				plan.getBindingNames());
	}

	private static CostVector lookupParentTotalCost(Winner child, double localLookupWork) {
		CostVector local = new CostVector(1.0d, localLookupWork, 0.0d, localLookupWork, 0.0d, 1.0d, 1.0d);
		return child.cost().plus(local).withRows(1.0d);
	}

	private static BindingProfile finiteProfile(String variable, Value value) {
		return finiteProfile(variable, value, "physical-fact-channel-test");
	}

	private static BindingProfile finiteProfile(String variable, Value value, String source) {
		FiniteRelationEstimate relation = FiniteRelationEstimate.fromRows(List.of(variable),
				List.of(List.of(value)), source);
		BagEstimate bag = BagEstimate.exact(1.0d, source)
				.withFiniteRelation(relation);
		return BindingProfile.fromBag(null, bag, Map.of());
	}

	private static BindingProfile exactProfile(List<String> variables, List<List<Value>> rows, String source) {
		FiniteRelationEstimate relation = FiniteRelationEstimate.fromRows(variables, rows, source);
		BagEstimate bag = BagEstimate.exact(rows.size(), source)
				.withFiniteRelation(relation);
		return BindingProfile.fromBag(null, bag, Map.of());
	}

	private static BindingProfile sketchProfile(String variable, DistributionSketch sketch) {
		BagEstimate bag = BagEstimate.exact(1.0d, "physical-fact-channel-sketch")
				.withVariable(variable, new VariableEstimate(1.0d, 1.0d, 0.0d, sketch));
		return BindingProfile.fromBag(null, bag, Map.of());
	}

	private static DistributionSketch productSketch() {
		return ProductDistributionSketch.join(new SemanticTestSketch(3.0d, 5.0d),
				new SemanticTestSketch(2.0d, 4.0d), 2.0d, 3.0d);
	}

	private static BindingProfile withEndpointMode(BindingProfile profile, String endpointMode) {
		return new BindingProfile(profile.variables(), profile.finiteRelations(), profile.finiteDomains(),
				profile.sketchRelations(), profile.jointDistinctRows(), profile.sketchVars(), profile.overlapEvidence(),
				endpointMode, profile.evidenceProfile());
	}

	private static int expectedGoalIdentityHash(OptimizationGoal goal) {
		int hash = 1;
		hash = combineHash(hash, expectedExecutionPropertyHash(goal.requiredProperties()));
		hash = combineHash(hash, goal.semanticScope());
		hash = combineHash(hash, goal.costPolicy());
		hash = combineHash(hash, goal.costBound());
		int excludedHash = goal.excludedProperties()
				.stream()
				.mapToInt(CascadesPhysicalFactChannelTest::expectedExecutionPropertyHash)
				.sum();
		hash = combineHash(hash, excludedHash);
		hash = combineHash(hash, goal.searchMode());
		hash = combineHash(hash, Long.hashCode(goal.deadlineNanos()));
		hash = combineHash(hash, goal.taskBudget());
		hash = combineHash(hash, goal.rowGoal());
		hash = combineHash(hash, goal.estimationTier());
		return combineHash(hash, goal.inputBindingContext());
	}

	private static int expectedWinnerIdentityHash(WinnerKey key) {
		int hash = 1;
		hash = combineHash(hash, key.groupId());
		hash = combineHash(hash, expectedExecutionPropertyHash(key.requiredProperties()));
		hash = combineHash(hash, key.semanticScope());
		hash = combineHash(hash, key.costPolicy());
		hash = combineHash(hash, key.rowGoal());
		return combineHash(hash, key.inputBindingContext());
	}

	private static int expectedExecutionPropertyHash(PhysicalProperties properties) {
		int hash = 1;
		hash = combineHash(hash, properties.ordering());
		hash = combineHash(hash, properties.distinctVars());
		hash = combineHash(hash, properties.accessPath());
		hash = combineHash(hash, properties.boundVars());
		hash = combineHash(hash, properties.inputBoundVars());
		hash = combineHash(hash, properties.materialization());
		hash = combineHash(hash, properties.graphContext());
		hash = combineHash(hash, properties.duplicateBehavior());
		hash = combineHash(hash, properties.observationOrder());
		hash = combineHash(hash, properties.inputConsumption());
		hash = combineHash(hash, properties.appliedFiniteRelations());
		return combineHash(hash, properties.bindingProfile().endpointMode());
	}

	private static int combineHash(int hash, Object value) {
		return 31 * hash + Objects.hashCode(value);
	}

	private static int combineHash(int hash, int value) {
		return 31 * hash + value;
	}

	private static StatementPattern pattern(String subject, String predicate, String object) {
		return new StatementPattern(new Var(subject), new Var(predicate), new Var(object));
	}

	private static Value iri(String value) {
		return SimpleValueFactory.getInstance().createIRI(value);
	}

	private static void drainChanges(Memo memo) {
		while (memo.pollChange().isPresent()) {
			// Drain initial import changes so later assertions can observe only the mutation under test.
		}
	}

	private record SemanticTestSketch(double distinctRows, double rows) implements DistributionSketch {

		@Override
		public OptionalDouble totalRows() {
			return OptionalDouble.of(rows);
		}
	}
